package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	mu      sync.RWMutex
	accounts map[string]int
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]int),
	}
}

func (b *Bank) Deposit(account string, amount int) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[account] += amount
}

func (b *Bank) Withdraw(account string, amount int) bool {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.accounts[account] < amount {
		return false
	}
	b.accounts[account] -= amount
	return true
}

func (b *Bank) Balance(account string) int {
	b.mu.RLock()
	defer b.mu.RUnlock()
	return b.accounts[account]
}

func main() {
	bank := NewBank()

	var wg sync.WaitGroup

	wg.Add(3)
	go func() {
		defer wg.Done()
		bank.Deposit("Alice", 100)
	}()

	go func() {
		defer wg.Done()
		if bank.Withdraw("Alice", 50) {
			fmt.Println("Withdrawal successful for Alice")
		} else {
			fmt.Println("Withdrawal failed for Alice")
		}
	}()

	go func() {
		defer wg.Done()
		fmt.Printf("Balance for Alice: %d\n", bank.Balance("Alice"))
	}()

	wg.Wait()
}